import scala.xml.XML
import scala.xml.Node

class ConfigurationService {
  def parseConfiguration(xmlString: String): Map[String, String] = {
    val xmlDoc = XML.loadString(xmlString)
    extractSettings(xmlDoc)
  }
  
  private def extractSettings(node: Node): Map[String, String] = {
    node match {
      case elem if elem.label == "configuration" =>
        elem \ "setting" map { setting =>
          val key = (setting \ "@name").text
          val value = (setting \ "@value").text
          key -> value
        } toMap
      case _ => Map.empty
    }
  }
  
  def parseWithEntities(xmlString: String): Map[String, String] = {
    val xmlDoc = XML.loadString(xmlString)
    extractSettings(xmlDoc)
  }
}